import type * as DMMF from '@prisma/dmmf'

import { fieldToTS, generateEnumType, generateInterface, mapScalarToTS, toModelPath } from './template'

/** Generate a complete typed REST client TypeScript file from DMMF. */
export function generateRestClient(dmmf: DMMF.Document): string {
  const sections: string[] = []

  sections.push(generateHeader())
  sections.push(generateConfigTypes())

  for (const enumDef of dmmf.datamodel.enums) {
    sections.push(generateEnumType(enumDef))
  }

  for (const model of dmmf.datamodel.models) {
    sections.push(generateModelTypes(model))
  }

  sections.push(generateClientClass(dmmf.datamodel.models))
  sections.push(generateFactory())

  return sections.join('\n\n') + '\n'
}

function generateHeader(): string {
  return [
    '// -------------------------------------------------------',
    '// This file was auto-generated by @prisma/generator-rest-client.',
    '// Do not edit manually.',
    '// -------------------------------------------------------',
  ].join('\n')
}

function generateConfigTypes(): string {
  return [
    'export interface RestClientConfig {',
    '  baseUrl: string',
    '  headers?: Record<string, string>',
    '  fetchFn?: typeof fetch',
    '}',
  ].join('\n')
}

function scalarFields(model: DMMF.Model): readonly DMMF.Field[] {
  return model.fields.filter((f) => f.kind !== 'object' && f.kind !== 'unsupported')
}

function identifierFields(model: DMMF.Model): readonly DMMF.Field[] {
  if (model.primaryKey) {
    const pkFieldNames = new Set(model.primaryKey.fields)
    return model.fields.filter((f) => pkFieldNames.has(f.name))
  }

  const idField = model.fields.find((f) => f.isId)
  if (idField) return [idField]

  const uniqueField = model.fields.find((f) => f.isUnique)
  if (uniqueField) return [uniqueField]

  return []
}

function generateModelTypes(model: DMMF.Model): string {
  const scalars = scalarFields(model)
  const idFields = identifierFields(model)

  const mainInterface = generateInterface(
    model.name,
    scalars.map((f) => ({ name: f.name, type: fieldToTS(f) })),
  )

  const createFields = scalars
    .filter((f) => !f.isReadOnly && !f.isUpdatedAt)
    .map((f) => {
      const isAutoId = f.isId && f.hasDefaultValue
      const optional = isAutoId || f.hasDefaultValue
      const type = fieldToTS(f)
      return { name: optional ? `${f.name}?` : f.name, type }
    })
  const createInput = generateInterface(`${model.name}CreateInput`, createFields)

  const updateFields = scalars
    .filter((f) => !f.isId && !f.isReadOnly && !f.isUpdatedAt)
    .map((f) => ({ name: `${f.name}?`, type: fieldToTS(f) }))
  const updateInput = generateInterface(`${model.name}UpdateInput`, updateFields)

  const parts = [mainInterface, createInput, updateInput]

  if (idFields.length > 0) {
    const whereFields = idFields.map((f) => ({ name: f.name, type: mapScalarToTS(f.type) }))
    parts.push(generateInterface(`${model.name}WhereUniqueInput`, whereFields))
  }

  return parts.join('\n\n')
}

function generateClientClass(models: readonly DMMF.Model[]): string {
  const lines: string[] = []

  lines.push('export class PrismaRestClient {')
  lines.push('  #baseUrl: string')
  lines.push('  #headers: Record<string, string>')
  lines.push('  #fetch: typeof fetch')
  lines.push('')
  lines.push('  constructor(config: RestClientConfig) {')
  lines.push('    this.#baseUrl = config.baseUrl.replace(/\\/$/, \'\')')
  lines.push('    this.#headers = config.headers ?? {}')
  lines.push('    this.#fetch = config.fetchFn ?? fetch')
  lines.push('  }')

  for (const model of models) {
    lines.push('')
    lines.push(generateModelAccessor(model))
  }

  lines.push('}')

  return lines.join('\n')
}

function generateModelAccessor(model: DMMF.Model): string {
  const name = model.name
  const path = toModelPath(name)
  const idFields = identifierFields(model)
  const hasId = idFields.length > 0

  const lines: string[] = []
  lines.push(`  get ${lowerFirst(name)}() {`)
  lines.push(`    const url = \`\${this.#baseUrl}/${path}\``)
  lines.push('    const headers = { ...this.#headers, \'Content-Type\': \'application/json\' }')
  lines.push('    const fetchFn = this.#fetch')
  lines.push('    return {')

  // findMany
  lines.push(`      async findMany(params?: { skip?: number; take?: number }): Promise<${name}[]> {`)
  lines.push('        const query = new URLSearchParams()')
  lines.push('        if (params?.skip !== undefined) query.set(\'skip\', String(params.skip))')
  lines.push('        if (params?.take !== undefined) query.set(\'take\', String(params.take))')
  lines.push('        const qs = query.toString()')
  lines.push('        const res = await fetchFn(`${url}${qs ? `?${qs}` : \'\'}`, { headers })')
  lines.push('        if (!res.ok) throw new Error(`GET ${url} failed: ${res.status}`)')
  lines.push('        return res.json()')
  lines.push('      },')

  if (hasId) {
    const whereType = `${name}WhereUniqueInput`
    const idParam = buildIdPathExpression(idFields)

    // findUnique
    lines.push(`      async findUnique(where: ${whereType}): Promise<${name} | null> {`)
    lines.push(`        const res = await fetchFn(\`\${url}/${idParam}\`, { headers })`)
    lines.push('        if (res.status === 404) return null')
    lines.push('        if (!res.ok) throw new Error(`GET failed: ${res.status}`)')
    lines.push('        return res.json()')
    lines.push('      },')

    // create
    lines.push(`      async create(data: ${name}CreateInput): Promise<${name}> {`)
    lines.push('        const res = await fetchFn(url, { method: \'POST\', headers, body: JSON.stringify(data) })')
    lines.push('        if (!res.ok) throw new Error(`POST ${url} failed: ${res.status}`)')
    lines.push('        return res.json()')
    lines.push('      },')

    // update
    lines.push(`      async update(where: ${whereType}, data: ${name}UpdateInput): Promise<${name}> {`)
    lines.push(`        const res = await fetchFn(\`\${url}/${idParam}\`, { method: 'PUT', headers, body: JSON.stringify(data) })`)
    lines.push('        if (!res.ok) throw new Error(`PUT failed: ${res.status}`)')
    lines.push('        return res.json()')
    lines.push('      },')

    // delete
    lines.push(`      async delete(where: ${whereType}): Promise<${name}> {`)
    lines.push(`        const res = await fetchFn(\`\${url}/${idParam}\`, { method: 'DELETE', headers })`)
    lines.push('        if (!res.ok) throw new Error(`DELETE failed: ${res.status}`)')
    lines.push('        return res.json()')
    lines.push('      },')
  } else {
    // create only (no unique identifier available for other operations)
    lines.push(`      async create(data: ${name}CreateInput): Promise<${name}> {`)
    lines.push('        const res = await fetchFn(url, { method: \'POST\', headers, body: JSON.stringify(data) })')
    lines.push('        if (!res.ok) throw new Error(`POST ${url} failed: ${res.status}`)')
    lines.push('        return res.json()')
    lines.push('      },')
  }

  lines.push('    }')
  lines.push('  }')

  return lines.join('\n')
}

/**
 * Build a template literal expression for constructing a URL path from
 * identifier fields, e.g. `${where.id}` or `${where.tenantId}/${where.userId}`.
 */
function buildIdPathExpression(idFields: readonly DMMF.Field[]): string {
  return idFields.map((f) => `\${where.${f.name}}`).join('/')
}

function lowerFirst(s: string): string {
  return s.charAt(0).toLowerCase() + s.slice(1)
}

function generateFactory(): string {
  return [
    'export function createRestClient(config: RestClientConfig): PrismaRestClient {',
    '  return new PrismaRestClient(config)',
    '}',
  ].join('\n')
}

