import type * as DMMF from '@prisma/dmmf'
import { describe, expect, it } from 'vitest'

import { generateRestClient } from '../generate-rest-client'
import { fieldToTS, generateEnumType, mapScalarToTS, toModelPath } from '../template'

// ---------------------------------------------------------------------------
// Helpers to construct minimal DMMF fixtures
// ---------------------------------------------------------------------------

function makeField(overrides: Partial<DMMF.Field> & { name: string; type: string }): DMMF.Field {
  return {
    kind: 'scalar',
    name: overrides.name,
    isRequired: true,
    isList: false,
    isUnique: false,
    isId: false,
    isReadOnly: false,
    type: overrides.type,
    hasDefaultValue: false,
    ...overrides,
  }
}

function makeModel(name: string, fields: DMMF.Field[], primaryKey: DMMF.PrimaryKey | null = null): DMMF.Model {
  return {
    name,
    dbName: null,
    schema: null,
    fields,
    uniqueFields: [],
    uniqueIndexes: [],
    primaryKey,
  }
}

function makeDmmf(
  models: DMMF.Model[],
  enums: DMMF.DatamodelEnum[] = [],
): DMMF.Document {
  return {
    datamodel: { models, enums, types: [], indexes: [] },
    schema: {
      inputObjectTypes: {},
      outputObjectTypes: { model: [], prisma: [] },
      enumTypes: { prisma: [] },
      fieldRefTypes: {},
    },
    mappings: { modelOperations: [], otherOperations: { read: [], write: [] } },
  }
}

// ---------------------------------------------------------------------------
// template.ts unit tests
// ---------------------------------------------------------------------------

describe('mapScalarToTS', () => {
  it.each([
    ['String', 'string'],
    ['Boolean', 'boolean'],
    ['Int', 'number'],
    ['Float', 'number'],
    ['BigInt', 'bigint'],
    ['Decimal', 'string'],
    ['DateTime', 'string'],
    ['Json', 'unknown'],
    ['Bytes', 'string'],
    ['Role', 'Role'],
  ])('maps %s to %s', (input, expected) => {
    expect(mapScalarToTS(input)).toBe(expected)
  })
})

describe('fieldToTS', () => {
  it('handles a required scalar', () => {
    expect(fieldToTS(makeField({ name: 'x', type: 'String' }))).toBe('string')
  })

  it('handles a nullable scalar', () => {
    expect(fieldToTS(makeField({ name: 'x', type: 'String', isRequired: false }))).toBe('string | null')
  })

  it('handles a list', () => {
    expect(fieldToTS(makeField({ name: 'x', type: 'Int', isList: true }))).toBe('number[]')
  })

  it('handles a nullable list', () => {
    expect(fieldToTS(makeField({ name: 'x', type: 'Int', isList: true, isRequired: false }))).toBe('number[] | null')
  })
})

describe('generateEnumType', () => {
  it('produces a union type', () => {
    const enumDef: DMMF.DatamodelEnum = {
      name: 'Role',
      values: [{ name: 'ADMIN', dbName: null }, { name: 'USER', dbName: null }],
    }
    expect(generateEnumType(enumDef)).toBe("export type Role = 'ADMIN' | 'USER'")
  })
})

describe('toModelPath', () => {
  it('lowercases model name', () => {
    expect(toModelPath('User')).toBe('user')
    expect(toModelPath('BlogPost')).toBe('blogpost')
  })
})

// ---------------------------------------------------------------------------
// generateRestClient integration tests
// ---------------------------------------------------------------------------

describe('generateRestClient', () => {
  const userModel = makeModel('User', [
    makeField({ name: 'id', type: 'Int', isId: true, hasDefaultValue: true }),
    makeField({ name: 'email', type: 'String', isUnique: true }),
    makeField({ name: 'name', type: 'String', isRequired: false }),
    makeField({ name: 'createdAt', type: 'DateTime', hasDefaultValue: true }),
