function makeField(overrides: Partial<DMMF.Field> & { name: string; type: string }): DMMF.Field {
  return {
    kind: 'scalar',
    name: overrides.name,
    isRequired: true,
    isList: false,
    isUnique: false,
    isId: false,
    isReadOnly: false,
    type: overrides.type,
    hasDefaultValue: false,
    ...overrides,
  }
}

function makeModel(name: string, fields: DMMF.Field[], primaryKey: DMMF.PrimaryKey | null = null): DMMF.Model {
  return {
    name,
    dbName: null,
    schema: null,
    fields,
    uniqueFields: [],
    uniqueIndexes: [],
    primaryKey,
  }
}

function makeDmmf(
  models: DMMF.Model[],
  enums: DMMF.DatamodelEnum[] = [],
): DMMF.Document {
  return {
    datamodel: { models, enums, types: [], indexes: [] },
    schema: {
      inputObjectTypes: {},
      outputObjectTypes: { model: [], prisma: [] },
      enumTypes: { prisma: [] },
      fieldRefTypes: {},
    },
    mappings: { modelOperations: [], otherOperations: { read: [], write: [] } },
  }
}

