    expect(fieldToTS(makeField({ name: 'x', type: 'Int', isList: true }))).toBe('number[]')
  })

  it('handles a nullable list', () => {
    expect(fieldToTS(makeField({ name: 'x', type: 'Int', isList: true, isRequired: false }))).toBe('number[] | null')
  })
